# ROBUSTNESS PHASE J — SOVD CDA semantic fidelity
# Manually written, not generated by testgen.py. Do not delete.
#
# Validates build_sovd_cda() output against the YAML that drives it.
# Imports build_sovd_cda and load_config directly from tools/codegen.py —
# no subprocess, no --sovd flag required. All tests are pure-Python, no
# xaloqi-tester or hardware needed.
#
# Run: pytest test_robustness_J_sovd_cda.py -v
from __future__ import annotations

import json
import os
import sys
import re

import pytest

EDS_ROOT  = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..", "..", ".."))
TOOLS_DIR = os.path.join(EDS_ROOT, "tools")
sys.path.insert(0, TOOLS_DIR)

from codegen import build_sovd_cda, load_config  # noqa: E402

from pathlib import Path

_CAN_YAML  = Path(EDS_ROOT) / "examples" / "basic_ecu"       / "diagnostics_config.yaml"
_DOIP_YAML = Path(EDS_ROOT) / "examples" / "basic_ecu_doip"  / "diagnostics_config.yaml"

# ── Helpers ──────────────────────────────────────────────────────────────────

def _load_cda(yaml_path: Path):
    cfg = load_config(yaml_path)
    return build_sovd_cda(cfg), cfg


def _yaml_dids(cfg):
    return cfg.get("dids", [])


def _yaml_dtcs(cfg):
    return cfg.get("dtcs", [])


def _yaml_routines(cfg):
    return cfg.get("routines", [])


def _hex_re():
    return re.compile(r"^0x[0-9A-Fa-f]+$")


# ── Class 1: Top-level CDA structure ─────────────────────────────────────────

class TestCDAStructure:
    """Top-level keys, version, generatedBy, timestamps, and ECU identity."""

    def setup_method(self):
        self.cda, self.cfg = _load_cda(_CAN_YAML)

    def test_required_top_level_keys_present(self):
        required = {
            "sovdVersion", "generatedBy", "generatedAt",
            "ecuIdentification", "transportInfo",
            "dataIdentifiers", "dtcs", "routines", "diagnosticServices",
        }
        missing = required - set(self.cda.keys())
        assert not missing, f"Missing top-level CDA keys: {missing}"

    def test_sovd_version_is_1_0_0(self):
        assert self.cda["sovdVersion"] == "1.0.0"

    def test_generated_by_mentions_xaloqi(self):
        assert "Xaloqi" in self.cda["generatedBy"], (
            f"generatedBy should mention Xaloqi, got: {self.cda['generatedBy']}")

    def test_generated_at_is_non_empty_string(self):
        ts = self.cda["generatedAt"]
        assert isinstance(ts, str) and len(ts) > 0, "generatedAt must be a non-empty string"

    def test_ecu_identification_has_name_and_version(self):
        eid = self.cda["ecuIdentification"]
        assert "name" in eid, "ecuIdentification missing 'name'"
        assert "version" in eid, "ecuIdentification missing 'version'"

    def test_ecu_name_matches_yaml(self):
        expected = self.cfg["metadata"]["ecu_name"]
        assert self.cda["ecuIdentification"]["name"] == expected, (
            f"ecuIdentification.name={self.cda['ecuIdentification']['name']!r} "
            f"!= YAML ecu_name={expected!r}")

    def test_ecu_version_matches_yaml(self):
        expected = self.cfg["metadata"]["version"]
        assert self.cda["ecuIdentification"]["version"] == expected

    def test_cda_is_json_serialisable(self):
        serialised = json.dumps(self.cda)
        recovered  = json.loads(serialised)
        assert recovered["sovdVersion"] == "1.0.0"


# ── Class 2: DID fidelity ─────────────────────────────────────────────────────

class TestCDADIDFidelity:
    """DID count, ID format, names, lengths, access, sessions, security levels."""

    def setup_method(self):
        self.cda, self.cfg = _load_cda(_CAN_YAML)
        self.dids     = self.cda["dataIdentifiers"]
        self.yaml_dids = _yaml_dids(self.cfg)

    def test_did_count_matches_yaml(self):
        assert len(self.dids) == len(self.yaml_dids), (
            f"CDA has {len(self.dids)} DIDs, YAML has {len(self.yaml_dids)}")

    def test_all_dids_have_required_keys(self):
        required = {"id", "name", "dataLengthBytes", "access", "minSession", "readSecurityLevel"}
        for did in self.dids:
            missing = required - set(did.keys())
            assert not missing, f"DID {did.get('id')} missing keys: {missing}"

    def test_did_ids_are_hex_normalised(self):
        pat = _hex_re()
        for did in self.dids:
            assert pat.match(did["id"]), (
                f"DID id {did['id']!r} is not a valid hex string (0xXXXX)")

    def test_did_names_match_yaml(self):
        cda_names  = [d["name"] for d in self.dids]
        yaml_names = [d["name"] for d in self.yaml_dids]
        assert cda_names == yaml_names, (
            f"DID name mismatch: CDA={cda_names}, YAML={yaml_names}")

    def test_did_data_lengths_match_yaml(self):
        for cda_did, yaml_did in zip(self.dids, self.yaml_dids):
            assert cda_did["dataLengthBytes"] == yaml_did.get("data_length"), (
                f"DID {cda_did['id']}: dataLengthBytes={cda_did['dataLengthBytes']} "
                f"!= YAML data_length={yaml_did.get('data_length')}")

    def test_did_access_lists_match_yaml(self):
        for cda_did, yaml_did in zip(self.dids, self.yaml_dids):
            assert cda_did["access"] == list(yaml_did.get("access", [])), (
                f"DID {cda_did['id']}: access mismatch")

    def test_did_min_session_is_semantic_string(self):
        valid = {"default", "extended", "programming"}
        for did in self.dids:
            assert did["minSession"] in valid, (
                f"DID {did['id']}: minSession={did['minSession']!r} is not a "
                f"semantic string — must be one of {valid}")

    def test_read_only_did_has_none_write_security_level(self):
        for cda_did, yaml_did in zip(self.dids, self.yaml_dids):
            access = yaml_did.get("access", [])
            if "write" not in access:
                assert cda_did.get("writeSecurityLevel") is None, (
                    f"Read-only DID {cda_did['id']} should have writeSecurityLevel=None, "
                    f"got {cda_did.get('writeSecurityLevel')!r}")

    def test_read_write_did_has_int_write_security_level(self):
        for cda_did, yaml_did in zip(self.dids, self.yaml_dids):
            access = yaml_did.get("access", [])
            if "write" in access:
                wsl = cda_did.get("writeSecurityLevel")
                assert isinstance(wsl, int), (
                    f"Read-write DID {cda_did['id']} writeSecurityLevel must be int, "
                    f"got {wsl!r}")

    def test_read_security_level_matches_yaml(self):
        for cda_did, yaml_did in zip(self.dids, self.yaml_dids):
            expected = yaml_did.get("read_security_level", 0)
            assert cda_did["readSecurityLevel"] == expected, (
                f"DID {cda_did['id']}: readSecurityLevel={cda_did['readSecurityLevel']} "
                f"!= YAML={expected}")


# ── Class 3: DTC fidelity ─────────────────────────────────────────────────────

class TestCDADTCFidelity:
    """DTC count, code format, description, severity values."""

    _VALID_SEVERITIES = {
        "immediate_display", "check_at_next_halt",
        "check_at_next_halt_ecu_reset", "maintenance_only",
    }

    def setup_method(self):
        self.cda, self.cfg = _load_cda(_CAN_YAML)
        self.dtcs      = self.cda["dtcs"]
        self.yaml_dtcs = _yaml_dtcs(self.cfg)

    def test_dtc_count_matches_yaml(self):
        assert len(self.dtcs) == len(self.yaml_dtcs), (
            f"CDA has {len(self.dtcs)} DTCs, YAML has {len(self.yaml_dtcs)}")

    def test_all_dtcs_have_required_keys(self):
        required = {"code", "description", "severity"}
        for dtc in self.dtcs:
            missing = required - set(dtc.keys())
            assert not missing, f"DTC missing keys: {missing}"

    def test_dtc_codes_are_hex_normalised(self):
        pat = _hex_re()
        for dtc in self.dtcs:
            assert pat.match(dtc["code"]), (
                f"DTC code {dtc['code']!r} is not a valid hex string")

    def test_dtc_descriptions_match_yaml(self):
        for cda_dtc, yaml_dtc in zip(self.dtcs, self.yaml_dtcs):
            expected = yaml_dtc.get("description", "")
            assert cda_dtc["description"] == expected, (
                f"DTC {cda_dtc['code']}: description mismatch")

    def test_dtc_severities_are_valid(self):
        for dtc in self.dtcs:
            assert dtc["severity"] in self._VALID_SEVERITIES, (
                f"DTC {dtc['code']}: severity={dtc['severity']!r} is not valid. "
                f"Must be one of {self._VALID_SEVERITIES}")

    def test_dtc_severity_matches_yaml(self):
        for cda_dtc, yaml_dtc in zip(self.dtcs, self.yaml_dtcs):
            expected = yaml_dtc.get("severity", "check_at_next_halt")
            assert cda_dtc["severity"] == expected, (
                f"DTC {cda_dtc['code']}: severity mismatch: "
                f"CDA={cda_dtc['severity']!r}, YAML={expected!r}")


# ── Class 4: Routine fidelity ─────────────────────────────────────────────────

class TestCDARoutineFidelity:
    """Routine count, ID format, names, sessions, security levels, sub-functions."""

    def setup_method(self):
        self.cda, self.cfg = _load_cda(_CAN_YAML)
        self.routines      = self.cda["routines"]
        self.yaml_routines = _yaml_routines(self.cfg)

    def test_routine_count_matches_yaml(self):
        assert len(self.routines) == len(self.yaml_routines), (
            f"CDA has {len(self.routines)} routines, YAML has {len(self.yaml_routines)}")

    def test_all_routines_have_required_keys(self):
        required = {"id", "name", "minSession", "securityLevel", "supportedSubFunctions"}
        for r in self.routines:
            missing = required - set(r.keys())
            assert not missing, f"Routine {r.get('id')} missing keys: {missing}"

    def test_routine_ids_are_hex_normalised(self):
        pat = _hex_re()
        for r in self.routines:
            assert pat.match(r["id"]), (
                f"Routine id {r['id']!r} is not a valid hex string")

    def test_routine_names_match_yaml(self):
        cda_names  = [r["name"]  for r in self.routines]
        yaml_names = [r["name"]  for r in self.yaml_routines]
        assert cda_names == yaml_names

    def test_routine_min_session_is_semantic_string(self):
        valid = {"default", "extended", "programming"}
        for r in self.routines:
            assert r["minSession"] in valid, (
                f"Routine {r['id']}: minSession={r['minSession']!r} not in {valid}")

    def test_routine_security_level_matches_yaml(self):
        for cda_r, yaml_r in zip(self.routines, self.yaml_routines):
            expected = yaml_r.get("security_level", 0)
            assert cda_r["securityLevel"] == expected, (
                f"Routine {cda_r['id']}: securityLevel={cda_r['securityLevel']} "
                f"!= YAML={expected}")

    def test_routine_supported_sub_functions_match_yaml(self):
        for cda_r, yaml_r in zip(self.routines, self.yaml_routines):
            expected = list(yaml_r.get("support", ["start"]))
            assert cda_r["supportedSubFunctions"] == expected, (
                f"Routine {cda_r['id']}: supportedSubFunctions={cda_r['supportedSubFunctions']} "
                f"!= YAML support={expected}")


# ── Class 5: Transport and DoIP fields ───────────────────────────────────────

class TestCDATransportAndDoIP:
    """Protocol field, DoIP fields present/absent, diagnostic service list."""

    def test_can_ecu_protocol_is_iso_tp(self):
        cda, _ = _load_cda(_CAN_YAML)
        assert cda["transportInfo"]["protocol"] == "ISO-TP", (
            f"CAN ECU must report ISO-TP, got {cda['transportInfo']['protocol']!r}")

    def test_can_ecu_no_logical_address(self):
        cda, _ = _load_cda(_CAN_YAML)
        assert "logicalAddress" not in cda["ecuIdentification"], (
            "CAN ECU must not have logicalAddress in ecuIdentification")

    def test_can_ecu_no_port_in_transport_info(self):
        cda, _ = _load_cda(_CAN_YAML)
        assert "port" not in cda["transportInfo"], (
            "CAN ECU must not have port in transportInfo")

    @pytest.mark.skipif(not _DOIP_YAML.is_file(), reason="basic_ecu_doip YAML not found")
    def test_doip_ecu_protocol_is_doip(self):
        cda, _ = _load_cda(_DOIP_YAML)
        assert cda["transportInfo"]["protocol"] == "DoIP"

    @pytest.mark.skipif(not _DOIP_YAML.is_file(), reason="basic_ecu_doip YAML not found")
    def test_doip_ecu_port_is_13400(self):
        cda, _ = _load_cda(_DOIP_YAML)
        assert cda["transportInfo"]["port"] == 13400

    @pytest.mark.skipif(not _DOIP_YAML.is_file(), reason="basic_ecu_doip YAML not found")
    def test_doip_ecu_logical_address_present(self):
        cda, _ = _load_cda(_DOIP_YAML)
        assert "logicalAddress" in cda["ecuIdentification"], (
            "DoIP ECU must have logicalAddress in ecuIdentification")

    @pytest.mark.skipif(not _DOIP_YAML.is_file(), reason="basic_ecu_doip YAML not found")
    def test_doip_ecu_logical_address_value(self):
        cda, _ = _load_cda(_DOIP_YAML)
        assert cda["ecuIdentification"]["logicalAddress"] == "0xE400"

    @pytest.mark.skipif(not _DOIP_YAML.is_file(), reason="basic_ecu_doip YAML not found")
    def test_doip_ecu_source_address_present(self):
        cda, _ = _load_cda(_DOIP_YAML)
        assert "sourceAddress" in cda["ecuIdentification"], (
            "DoIP ECU must have sourceAddress in ecuIdentification")

    def test_both_transport_ecu_produces_doip_protocol(self):
        """'both' transport → DoIP is the wire protocol, not ISO-TP."""
        import yaml as _yaml
        raw = _yaml.safe_load(_DOIP_YAML.read_text())
        raw["ecu"]["transport"] = "both"
        cda = build_sovd_cda(raw)
        assert cda["transportInfo"]["protocol"] == "DoIP", (
            f"transport='both' must yield protocol=DoIP, got {cda['transportInfo']['protocol']!r}")

    def test_diagnostic_services_count_is_14(self):
        cda, _ = _load_cda(_CAN_YAML)
        assert len(cda["diagnosticServices"]) == 14, (
            f"Expected 14 diagnosticServices, got {len(cda['diagnosticServices'])}")

    def test_diagnostic_services_have_sid_and_name(self):
        cda, _ = _load_cda(_CAN_YAML)
        for svc in cda["diagnosticServices"]:
            assert "sid" in svc and "name" in svc, (
                f"Service entry missing sid or name: {svc}")

    def test_cda_idempotent_across_two_calls(self):
        """Two calls with the same config must produce identical content (except generatedAt)."""
        cfg  = load_config(_CAN_YAML)
        cda1 = build_sovd_cda(cfg)
        cda2 = build_sovd_cda(cfg)
        cda1.pop("generatedAt")
        cda2.pop("generatedAt")
        assert cda1 == cda2, "build_sovd_cda is not idempotent"
